Kaj izpiše naslednji program? 
Pascal: 
C: 
var a,b,c : integer; 
#include <stdio.h> 
begin 
int main() 
  a:=17; b:=3; c:=0; 
{ 
  while (a>b) do begin 
  int a=17,b=3,c=0; 
    inc(c); 
  while (a>b) { 
    a:=a-b; 
    c++; 
  end; 
    a-=b; 
  writeln(c,' ',a); 
  } 
end. 
  printf("%d %d\n",c,a); 
  return 0; 
} 
