begin 
   for stevilo := 1 to 10 do 
     begin 
      writeln('stevilo: ',stevilo); 
      writeln('kvadrat: ',sqr(stevilo)); 
      writeln('kub: ',stevilo*(sqr(stevilo))); 
     end; 
end. 
